// <auto-generated/>
using Karpik.Engine.Core.ModuleManagement;
using System;
using System.Collections;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Reflection;
using System.Runtime.Loader;

public class ModuleLoader
{
    public Assembly[] LoadedAssemblies = [];
    private AssemblyLoadContext? _currentContext;
    private WeakReference<AssemblyLoadContext>? _previousContext;
    private WeakReference a;
    private string? _directoryToCleanup;

    public readonly string[] SharedAssemblies = {
        "AssetManagement.Core",
        "DebugModule",
        "ECS.Core",
        "LoggerModule",
        "Modding.Core",
        "Modding.Lua",
        "Network.Shared.Core",
        "Network.Shared.LiteNetLib",
        "StatAndAbilities",
        "Tween.Core",
        "MyGameResources",
        "MyGame.Shared.Main",
    };
    public readonly string[] ClientOnlyAssemblies = {
        "Graphics.Core",
        "Graphics.Raylib",
        "Input",
        "Network.Client.Core",
        "Network.Client.LiteNetLib",
        "UIToolkit.Core",
        "MyGame.Client.Main",
    };
    public readonly string[] ServerOnlyAssemblies = {
        "Network.Server.Core",
        "Network.Server.LiteNetLib",
        "MyGame.Server.Main",
    };

    public void LoadClientModules() => LoadPluginCollection(SharedAssemblies.Concat(ClientOnlyAssemblies));
    public void LoadServerModules() => LoadPluginCollection(SharedAssemblies.Concat(ServerOnlyAssemblies));

    public void LoadPluginCollection(IEnumerable<string> assemblyNames)
    {
        var sourceDirectory = Path.Combine(AppContext.BaseDirectory, "modules");
        _directoryToCleanup = Path.Combine(AppContext.BaseDirectory, "temp_bin", Guid.NewGuid().ToString());
        Directory.CreateDirectory(_directoryToCleanup);

        var allDlls = Directory.GetFiles(sourceDirectory, "*.dll", SearchOption.AllDirectories);
        foreach (var dllPath in allDlls)
        {
            var fileName = Path.GetFileName(dllPath);
            File.Copy(dllPath, Path.Combine(_directoryToCleanup, fileName), true);

            var pdbPath = Path.ChangeExtension(dllPath, ".pdb");
            if (File.Exists(pdbPath))
                File.Copy(pdbPath, Path.Combine(_directoryToCleanup, Path.GetFileName(pdbPath)), true);
        }
        
        var newContext = new PluginLoadContext(_directoryToCleanup);
        _currentContext = newContext;

        var loadedList = new List<Assembly>();

        foreach (var name in assemblyNames.Distinct())
        {
            var shadowPath = Path.Combine(_directoryToCleanup, name + ".dll");
            if (File.Exists(shadowPath))
            {
                var asm = newContext.LoadFromAssemblyPath(shadowPath);
                loadedList.Add(asm);
            }
            else
            {
                Console.WriteLine($"[ModuleLoader] Assembly not found: {shadowPath}");
            }
        }

        LoadedAssemblies = loadedList.ToArray();
    }

    public void Unload()
    {
        CleanupStaticFields(_currentContext.Assemblies);
        if (_currentContext.Assemblies != null)
        {
            foreach (var asm in _currentContext.Assemblies)
            {
                foreach (var type in asm.GetTypes())
                {
                    System.ComponentModel.TypeDescriptor.Refresh(type);
                }
                System.ComponentModel.TypeDescriptor.Refresh(asm);
            }
        }

        LoadedAssemblies = null;

        for (int i = 0; i < 100; i++)
        {
            GC.Collect(GC.MaxGeneration);
            GC.WaitForPendingFinalizers();
        }
        GC.Collect(GC.MaxGeneration, GCCollectionMode.Aggressive);
        GC.WaitForFullGCApproach(-1);

        _currentContext.Unload();

        for (int i = 0; i < 100; i++)
        {
            GC.Collect(GC.MaxGeneration);
            GC.WaitForPendingFinalizers();
        }
        GC.Collect(GC.MaxGeneration, GCCollectionMode.Aggressive);
        GC.WaitForFullGCApproach(-1);
        
        _previousContext = new WeakReference<AssemblyLoadContext>(_currentContext);
        a = new WeakReference(_currentContext);
        _currentContext = null;
    }

    public void CheckForPreviousContextUnload()
    {
        for (int i = 0; i < 100; i++)
        {
            GC.Collect(GC.MaxGeneration);
            GC.WaitForPendingFinalizers();
        }
        
        GC.Collect(GC.MaxGeneration, GCCollectionMode.Aggressive);
        GC.WaitForFullGCApproach(-1);

        if (a.IsAlive)
        {
            _previousContext.TryGetTarget(out var context);
            Console.ForegroundColor = ConsoleColor.Red;
            Console.WriteLine($"Unloaded assemblies: {context.Assemblies.Count()}");
            foreach (var assembly in context.Assemblies)
            {
                Console.WriteLine(assembly.FullName);
            }
            Console.WriteLine("[ModuleLoader] FATAL: Previous AssemblyLoadContext is still alive after GC. A strong reference is likely leaking.");
            Console.ResetColor();
        }
        else
        {
            Console.WriteLine("[ModuleLoader] Previous context successfully collected by GC.");

            if (_directoryToCleanup != null)
            {
                try
                {
                    Directory.Delete(_directoryToCleanup, true);
                    Console.WriteLine($"[ModuleLoader] Successfully cleaned up old shadow directory.");
                }
                catch (Exception e)
                {
                    Console.ForegroundColor = ConsoleColor.Red;
                    Console.WriteLine($"[ModuleLoader] ERROR: Failed to cleanup directory: {e.Message}");
                    Console.ResetColor();
                }
                _directoryToCleanup = null;
            }
        }
    }

    public static void CleanupStaticFields(IEnumerable<Assembly> assemblies)
    {
        var fields = assemblies
            .SelectMany(x => x.GetTypes())
            .SelectMany(type => type.GetFields(BindingFlags.Static | BindingFlags.Public | BindingFlags.NonPublic))
            .Where(x => !x.FieldType.IsValueType
                        // && !x.IsLiteral && !x.IsInitOnly
                        );
        
        foreach (var field in fields)
        {
            try
            {
                if (field.FieldType.IsArray)
                {
                    var array = field.GetValue(null) as Array;
                    if (array is not null)
                    {
                        Array.Clear(array);
                    }
                }
                else if (typeof(IDictionary).IsAssignableFrom(field.FieldType))
                {
                    var dict = (IDictionary)field.GetValue(null);
                    dict.Clear();
                }
                else if (typeof(IList).IsAssignableFrom(field.FieldType))
                {
                    var list = (IList)field.GetValue(null);
                    list.Clear();
                }
                else if (typeof(IEnumerable).IsAssignableFrom(field.FieldType) && field.FieldType != typeof(string))
                {
                    var clearMethod = field.FieldType.GetMethod("Clear");
                    clearMethod?.Invoke(field.GetValue(null), null);
                }
                else
                {
                    // Зануляем ссылку
                    field.SetValue(null, null);
                }
            }
            catch (Exception ex)
            {
                // Некоторые поля (например, генерируемые компилятором или специфические readonly) 
                // могут сопротивляться занулению. В контексте выгрузки это можно проигнорировать.
                Console.WriteLine($"Failed to null {field.Name} in {field.Name}: {ex.Message}");
            }
        }
    }
}
